import{_ as a,o,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"1979年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1979年/核心总结.md","filePath":"01_letters/1979年/核心总结.md"}'),e={name:"01_letters/1979年/核心总结.md"};function i(n,t,s,u,h,q){return o(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="_1979年巴菲特致股东的信核心总结" tabindex="-1">1979年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1979年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1979年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1979年是巴菲特执掌伯克希尔的第15个年头，这一年最大的背景是美国高通胀，巴菲特罕见地讨论了通胀对投资者实际回报的侵蚀，提出了著名的&quot;投资者痛苦指数&quot;，同时对长期债券发出了深刻警告，这份警告放在今天依然振聋发聩。这封信还清晰展现了巴菲特一直延续到现在的公司治理和股东沟通哲学。文末可下载英文原版PDF。</p><h2 id="一、核心观点-衡量业绩-看透通胀" tabindex="-1">一、核心观点：衡量业绩，看透通胀 <a class="header-anchor" href="#一、核心观点-衡量业绩-看透通胀" aria-label="Permalink to &quot;一、核心观点：衡量业绩，看透通胀&quot;">​</a></h2><ul><li><strong>依然坚持用ROE衡量业绩</strong>：每股收益增长会骗人，因为股本不断变大，就像储蓄账户复利自然会让利息每年增长，&quot;哪怕停摆的钟，只要低股息，看起来都像成长股&quot;。管理好坏看的是<strong>投入资本回报率</strong>，不是每股收益增长。</li><li>长期结果：从1964年到1979年，每股账面价值从19.46美元涨到335.85美元，<strong>年复利20.5%</strong>。</li><li><strong>通胀是投资者最大敌人</strong>：巴菲特提出&quot;投资者痛苦指数&quot;=通胀率+交税比例（你把收益拿出来需要交的税率）。当这个指数超过企业股权回报率，你哪怕不消费，购买力都会缩水。现在20%复利，14%通胀，税后购买力增长几乎是零！就像1964年能买半盎司黄金，15年后还是只能买半盎司黄金，纸面增长都是通胀带来的。</li></ul><h2 id="二、各业务板块" tabindex="-1">二、各业务板块 <a class="header-anchor" href="#二、各业务板块" aria-label="Permalink to &quot;二、各业务板块&quot;">​</a></h2><h3 id="_1-纺织和零售-教训总结" tabindex="-1">1. 纺织和零售：教训总结 <a class="header-anchor" href="#_1-纺织和零售-教训总结" aria-label="Permalink to &quot;1. 纺织和零售：教训总结&quot;">​</a></h3><ul><li>零售：联合零售本·罗斯纳76岁依然神奇，不增长的行业，靠着极强成本控制，常年ROI 20%，是小而美的典范。</li><li>纺织：巴菲特坦诚自己收购Waumbec Mills是错误：&quot;便宜价格买烂生意，不如公平价格买好生意&quot;，&quot;扭转失败很少真能成功，精力才能最好用在别处&quot;。</li></ul><h3 id="_2-保险承保-预测应验-纪律制胜" tabindex="-1">2. 保险承保：预测应验，纪律制胜 <a class="header-anchor" href="#_2-保险承保-预测应验-纪律制胜" aria-label="Permalink to &quot;2. 保险承保：预测应验，纪律制胜&quot;">​</a></h3><ul><li>去年预测行业综合成本率会上升到亏损，应验了，行业从97.4%升到100.7%。伯克希尔反而从98.2%降到97.1%，相对改善。</li><li><strong>典范就是菲尔·利切</strong>：8200万保费赚840万承保利润，行业顶级。真正做到了&quot;不划算就缩量&quot;，大多数经理嘴上说，很少真做。&quot;我们宁愿偶尔闲一点，也不逼着大家写亏钱的生意&quot;，这种纪律说起来容易做起来难。</li><li><strong>对未来判断</strong>：未来五年行业平均综合成本率会到105，因为高利率鼓励大家接受承保亏损失换投资资金，行业对亏损容忍度会更高。</li><li>亮点：塞浦路斯工人补偿收购是&quot;绝对宝石&quot;，能力符合，纪律严明，结果非常好。</li></ul><h3 id="_3-保险投资-对长期债券的警告-这部分是这封信最大亮点" tabindex="-1">3. 保险投资：对长期债券的警告（这部分是这封信最大亮点） <a class="header-anchor" href="#_3-保险投资-对长期债券的警告-这部分是这封信最大亮点" aria-label="Permalink to &quot;3. 保险投资：对长期债券的警告（这部分是这封信最大亮点）&quot;">​</a></h3><ul><li>股权持仓继续表现好，GEICO已经成为最大持仓，巴菲特还是老办法：买优秀公司，留着让它们赚留存收益再帮我们赚钱。</li><li><strong>重点聊债券</strong>：保险行业在长期债券上亏了大钱，会计准则帮了倒忙——允许按摊余成本持有，不用盯市值，结果大家一直装睡，问题攒到很大才发现。</li><li><strong>最讽刺的矛盾</strong>：保险公司都说通胀时代一年期汽车保单都太长，不敢定一年价格，改成半年。但转头就把钱拿去放30-40年长期固定利率债券！</li><li><strong>这个时代没人敢锁长期价格</strong>：现在所有东西都没人敢固定价格到几年后，只有长期债券还在这么干，这是文化滞后。</li><li><strong>巴菲特做法</strong>：很早就不买纯长期固定债券了，只买可转换债券——转换期权相当于给了你退出机会，实际久期短很多。结论：&quot;在美元不断贬值的世界，长期固定利率债券不是合适的投资工具&quot;，巴菲特引用波洛尼厄斯改了一下：&quot;别做短期借款人，也别做长期贷款人&quot;。</li></ul><h3 id="_4-银行业-最后一年-即将剥离" tabindex="-1">4. 银行业：最后一年，即将剥离 <a class="header-anchor" href="#_4-银行业-最后一年-即将剥离" aria-label="Permalink to &quot;4. 银行业：最后一年，即将剥离&quot;">​</a></h3><ul><li>这是最后一年作为子公司报告，吉恩·阿贝格再次交出非凡成绩，ROA 2.3%，是大银行平均三倍。因为法令要求剥离，美联储禁止分拆后伯克希尔高管兼任，所以可能要卖掉，会优先找对管理层好的买家，不只看价格。巴菲特也坦言：&quot;卖掉后你根本没法用同样价格再买到同等质量的生意&quot;。</li></ul><h2 id="三、巴菲特的公司治理哲学-非常值得读" tabindex="-1">三、巴菲特的公司治理哲学（非常值得读） <a class="header-anchor" href="#三、巴菲特的公司治理哲学-非常值得读" aria-label="Permalink to &quot;三、巴菲特的公司治理哲学（非常值得读）&quot;">​</a></h2><ul><li>伯克希尔股东非常特别：98%股份是去年股东继续持有，90%股东伯克希尔是他们最大持仓，愿意花时间读年报。所以我们年报讲新东西，不重复老内容。</li><li>我们季报不写长文，因为我们都是长期视角，每个季度没那么多新东西好说。</li><li><strong>重要原则</strong>：所有者有权直接听CEO说真话，就像私人公司一样，一年一次不说公关辞令，讲真话。</li><li><strong>公司吸引什么样的股东，是自己选的</strong>：你聚焦短期，就吸引短期股东；你诚实，就吸引诚实的长期股东。巴菲特引用费雪：餐厅定位什么客户，就会吸引什么客户，不能一会儿做中餐一会儿做西餐，最后客人都不满意。</li><li><strong>我们不追求高换手</strong>：我们希望股东喜欢我们的&quot;菜单&quot;，年复一年来，现在这群股东已经是最好的了，就想保持低换手。</li></ul><h2 id="四、核心启示" tabindex="-1">四、核心启示 <a class="header-anchor" href="#四、核心启示" aria-label="Permalink to &quot;四、核心启示&quot;">​</a></h2><ol><li><strong>通胀是投资者看不见的小偷</strong>：20%名义回报在14%通胀下，税后实际回报几乎为零，这个道理放在今天依然适用。 2<strong>逆市投资需要勇气</strong>：1970年代末机构对股市极度悲观，巴菲特一直在不断重仓买优质公司，后来证明这是伯克希尔飞起来的起点。 3<strong>纪律比扩张重要</strong>：保险生意不划算就缩量，宁愿闲着也不亏钱赚吆喝，这种纪律是长期存活的关键。 4<strong>别做长期固定利率贷款人</strong>：通胀时代，长期债券就是对赌政府能控制通胀，这个赌赢少输多。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201979.pdf">巴菲特1979年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',20)])])}const _=a(e,[["render",i]]);export{g as __pageData,_ as default};
